+func TestRestorer_loadPaneScrollback_Compressed(t *testing.T) {
+	tmpDir, err := os.MkdirTemp("", "ntm-restore-test")
+	if err != nil {
+		t.Fatalf("Failed to create temp dir: %v", err)
